game_info.concept:
{
  "original_game_name": "Skat Treff: Werde Skat Meister",
  "game_name": "Skat Solo Challenge",
  "genre": "Card Game, Trick-taking, Strategy",
  "core_mechanics": {
    "player_actions": [
      {
        "action": "Select Card from Hand",
        "trigger": "Click on card in player's hand, or use ArrowLeft/ArrowRight to cycle selection."
      },
      {
        "action": "Play Card",
        "trigger": "Click on selected card, or press Space, when it's player's turn and card is valid for play."
      },
      {
        "action": "Bid Value",
        "trigger": "Click 'Bid X' button on UI, or press 'W' / 'ArrowUp' to increase bid (cycles through valid bids if implemented as a single button, or confirms selected bid).",
        "notes": "Player can only bid higher than previous bid."
      },
      {
        "action": "Pass Bid",
        "trigger": "Click 'Pass' button on UI, or press 'S' / 'ArrowDown'."
      },
      {
        "action": "Take Skat",
        "trigger": "Click on Skat cards in center, or press Shift (when declarer and in Skat phase)."
      },
      {
        "action": "Discard Cards",
        "trigger": "Select two cards from hand (now 12 cards), then click 'Discard' button or press 'Z' for each card to discard (or once to confirm after two are selected).",
        "notes": "Declarer must discard exactly two cards after taking the Skat."
      },
      {
        "action": "Select Game Type",
        "trigger": "Click on specific game type buttons (e.g., 'Clubs', 'Spades', 'Grand', 'Null') on UI (when declarer and in game type selection phase)."
      }
    ],
    "game_rules_systems": [
      "Single Player vs. 2 AI Opponents: All gameplay revolves around the human player competing against two computer-controlled opponents.",
      "32-Card Deck: Standard German-suited 32-card deck (7, 8, 9, 10, Jack, Queen, King, Ace in each of 4 suits: Clubs, Spades, Hearts, Diamonds).",
      "Dealing: 10 cards dealt to each player, 2 cards form the 'Skat' in the center.",
      "Bidding Phase: Players (human and AI) bid based on potential game value. Highest bidder becomes the 'declarer'. AI bidding is based on simplified heuristics.",
      "Skat Phase: Declarer takes the 2 'Skat' cards into their hand, then discards any 2 cards. These discarded cards count towards the declarer's trick points at the end of the round.",
      "Game Type Selection: Declarer chooses the 'game type' (e.g., a specific trump suit like 'Clubs', 'Grand' where Jacks are trumps, or 'Null' where no trumps exist and objective is to take no tricks).",
      "Trick-Taking: Players play cards in sequence. The first player to play in a trick determines the 'led suit'. Subsequent players must 'follow suit' if able. If not, they may play a trump card or any other card. The highest trump wins the trick; if no trumps are played, the highest card of the led suit wins. The winner of a trick leads the next trick. (Standard Skat rules apply for trump hierarchy and trick-winning).",
      "Card Points: Standard Skat card point values are used for collected tricks (Ace: 11, Ten: 10, King: 4, Queen: 3, Jack: 2, Nine: 0, Eight: 0, Seven: 0). Total card points in the deck: 120.",
      "Round Objective: Declarer aims to collect cards totaling at least 61 card points from their tricks and the discarded Skat cards. Opponents collaborate to prevent the declarer from reaching 61 points."
    ],
    "state_tracking": [
      "Deck: Array of Card objects (suit, rank, point value).",
      "Player Hands: Array of 3 arrays, each holding Card objects for a player's hand.",
      "Skat Cards: Array of 2 Card objects.",
      "Played Cards (Current Trick): Array of Card objects currently in play for the trick.",
      "Collected Tricks: Array of 3 arrays, each holding Card objects collected by a player from won tricks.",
      "Current Player Turn: Index (0-2) indicating whose turn it is.",
      "Declarer: Player index (0-2) of the round's declarer.",
      "Current Bid Value: Integer representing the highest bid.",
      "Game Type: String ('Clubs', 'Spades', 'Hearts', 'Diamonds', 'Grand', 'Null').",
      "Trump Suit: String (or 'None' for Null game).",
      "Round Declarer Points: Integer, total card points collected by the declarer.",
      "Round Opponent Points: Integer, total card points collected by the opponents.",
      "Round Outcome: String ('DeclarerWin', 'OpponentWin').",
      "Game Level: Integer representing current level (1-3).",
      "Player Cumulative Score: Integer, total score across all completed rounds/levels for the human player."
    ]
  },
  "visual_elements": {
    "game_objects": [
      "Cards (32 instances)",
      "Player Hand Area (Human)",
      "AI Player Hand Areas (2 instances)",
      "Skat Card Area (center table)",
      "Trick Playing Area (center table)",
      "Bidding UI (buttons, current bid text)",
      "Game Type Selection UI (buttons)",
      "Score Display (cumulative and round-specific)",
      "Turn Indicator",
      "Game Status Messages (e.g., 'Player X's Turn', 'Declarer Wins!')",
      "Level Indicator",
      "Main Menu Buttons",
      "Game Setup Options (deck design selectors)",
      "High Score Table"
    ],
    "visual_representations": [
      "Cards: Rectangular shapes. Front: Suit icon (e.g., Unicode symbols or small images) and rank text (7, 8, 9, 10, J, Q, K, A). Back: Generic patterned design. Three selectable card back designs ('Classic', 'Modern', 'Cartoon'). Size: Approx. 70x100 pixels. Selected card in hand will have a glowing border or slight elevation.",
      "Table Background: Static green felt texture, filling the canvas.",
      "Player Hand: Cards fanned out along the bottom edge of the screen. Overlapping slightly, allowing rank/suit to be visible. Hover effect on cards.",
      "AI Hands: Represented as two stacks of face-down cards on the top and left/right sides of the screen, with a small name tag (e.g., 'AI Opponent 1').",
      "Skat: Two face-down cards positioned centrally on the table.",
      "Trick Area: Played cards from current trick arranged in a small circular or linear layout in the center of the table, face up.",
      "UI Elements: Buttons (rectangles with text), text displays (scores, bids, status) in a clear, readable font. Color scheme to match card game aesthetic (e.g., muted greens, browns, creams).",
      "Level Indicator: Text displaying 'Level X / Y' and 'Round Z / W' positioned in the top-left or top-center."
    ],
    "animations_visual_effects": [
      "Card Dealing: Cards smoothly fly from a 'deck' position (off-screen or designated area) to player hands and Skat positions.",
      "Card Play: Selected card from hand smoothly glides to its position in the trick area.",
      "Trick Collection: Cards from the trick area visually 'sweep' towards the trick winner's collected pile, possibly with a subtle sparkle or glow effect.",
      "Bidding Highlights: Bid buttons glow or change color when active or selected.",
      "Game State Transitions: Fade-in/out effects for menu screens, level completion screens.",
      "Winning/Losing Effects: Short celebratory animation (e.g., confetti) for round/level wins, or a subtle 'game over' visual for losses."
    ]
  },
  "control_scheme": {
    "primary_controls": "Mouse/Touch for selecting cards, clicking UI buttons.",
    "keyboard_controls": [
      {
        "key": "ArrowLeft / A",
        "action": "Select previous card in player's hand (cycles through cards)."
      },
      {
        "key": "ArrowRight / D",
        "action": "Select next card in player's hand (cycles through cards)."
      },
      {
        "key": "Space",
        "action": "Play currently selected card from hand (if valid and player's turn)."
      },
      {
        "key": "W / ArrowUp",
        "action": "Bid (if bidding UI is active; can cycle through available bids or confirm)."
      },
      {
        "key": "S / ArrowDown",
        "action": "Pass (if bidding UI is active; confirms pass)."
      },
      {
        "key": "Shift",
        "action": "Look at Skat cards (if declarer and in Skat phase)."
      },
      {
        "key": "Z",
        "action": "Discard selected card (if declarer, Skat taken, and 2 cards need to be discarded. Select card with ArrowLeft/Right first)."
      }
    ]
  },
  "game_states": [
    {
      "state": "MainMenu",
      "description": "Initial screen with 'Start Game', 'Options' (for card design), and 'High Scores'.",
      "trigger": "Game launch, returning from GameEnd/GameWin/LevelTransition.",
      "transition_to": [
        "GameSetup",
        "Options",
        "HighScores"
      ]
    },
    {
      "state": "GameSetup",
      "description": "Allows selection of card deck design.",
      "trigger": "Click 'Start Game' from MainMenu.",
      "transition_to": [
        "BiddingPhase"
      ]
    },
    {
      "state": "BiddingPhase",
      "description": "Players (human and AI) bid to determine the declarer. UI displays current bid and buttons for 'Bid'/'Pass'.",
      "trigger": "Start of a new round (after GameSetup or previous RoundEnd).",
      "transition_to": [
        "SkatPhase"
      ]
    },
    {
      "state": "SkatPhase",
      "description": "The declarer takes the two Skat cards into their hand, then discards two cards. UI for viewing Skat and selecting discards.",
      "trigger": "BiddingPhase concludes, declarer determined.",
      "transition_to": [
        "GameTypeSelection"
      ]
    },
    {
      "state": "GameTypeSelection",
      "description": "The declarer chooses the trump suit or game type (e.g., Grand, Null). UI with game type buttons.",
      "trigger": "SkatPhase concludes.",
      "transition_to": [
        "GamePlayPhase"
      ]
    },
    {
      "state": "GamePlayPhase",
      "description": "Core trick-taking gameplay. Players play cards, tricks are won, points accumulated. Turn indicator visible.",
      "trigger": "GameTypeSelection concludes.",
      "transition_to": [
        "RoundEnd"
      ],
      "notes": "Loops for 10 tricks."
    },
    {
      "state": "RoundEnd",
      "description": "Displays the points collected by declarer and opponents for the completed round, and declares the round winner. Updates cumulative score.",
      "trigger": "All 10 tricks of GamePlayPhase are completed.",
      "transition_to": [
        "LevelTransition"
      ]
    },
    {
      "state": "LevelTransition",
      "description": "After a set number of rounds for a level, this screen shows if the level was won or lost, the overall score for that level, and prompts to continue or return to menu.",
      "trigger": "A level's round quota is met (e.g., 2 out of 3 rounds won).",
      "transition_to": [
        "BiddingPhase",
        "GameOver",
        "GameWin",
        "MainMenu"
      ]
    },
    {
      "state": "GameOver",
      "description": "Displayed if player fails a level. Shows final cumulative score and options to return to Main Menu.",
      "trigger": "Player loses a level.",
      "transition_to": [
        "MainMenu"
      ]
    },
    {
      "state": "GameWin",
      "description": "Displayed if player completes all levels. Shows 'Skat Master!' message and final cumulative score.",
      "trigger": "Player successfully completes the final level.",
      "transition_to": [
        "MainMenu"
      ]
    }
  ],
  "win_conditions": {
    "round_win_declarer": "Declarer (human player or AI) collects at least 61 card points from their tricks and the Skat cards.",
    "round_win_opponents": "Opponents (human player or AI) collectively prevent the declarer from reaching 61 card points (i.e., declarer gets < 61 points).",
    "level_win": "The human player successfully wins 2 out of 3 rounds within the current level, regardless of whether they were declarer or opponent.",
    "overall_game_win": "The human player successfully completes all 3 levels of the game."
  },
  "lose_conditions": {
    "round_lose_declarer": "Declarer (human player or AI) collects less than 61 card points.",
    "round_lose_opponents": "Opponents (human player or AI) fail to prevent declarer from reaching 61 card points (i.e., declarer gets >= 61 points).",
    "level_lose": "The human player loses 2 out of 3 rounds within the current level. This triggers a 'Game Over'.",
    "overall_game_lose": "The human player fails any level (i.e., reaches the level lose condition)."
  },
  "scoring_system": {
    "display_location": {
      "cumulative_game_score": "Top-right corner of the screen during gameplay: 'SCORE: [Player's Cumulative Score]'",
      "round_score": "Temporary popup at the end of each round: 'Declarer Points: XX', 'Opponent Points: YY', 'Round Winner: [Player/AI Name]'",
      "high_score_table": "Dedicated 'High Scores' screen accessible from Main Menu, displaying top 5 entries (Player Name, Score)."
    },
    "actions_giving_points": [
      {
        "action": "Winning a round as Declarer",
        "points": "+100 to cumulative score"
      },
      {
        "action": "Winning a round as Opponent",
        "points": "+50 to cumulative score"
      },
      {
        "action": "Winning a round with 'Schneider' (opponent scores < 31 points)",
        "points": "+25 bonus to cumulative score"
      },
      {
        "action": "Winning a round with 'Schwarz' (opponent scores 0 points)",
        "points": "+50 bonus to cumulative score"
      },
      {
        "action": "Winning a 'Grand' game (as declarer)",
        "points": "+50 bonus to cumulative score"
      },
      {
        "action": "Successfully completing a Level",
        "points": "+200 to cumulative score"
      }
    ],
    "bonus_points_multipliers": "Bonus points as described for 'Schneider', 'Schwarz', and 'Grand' games. No other multipliers implemented for simplification.",
    "high_score_system": "Yes, stores the top 5 player names and their final cumulative scores locally using `localStorage`.",
    "score_affects_gameplay": "The cumulative score determines the player's ranking on the high score list and is the primary metric for overall game performance, though not directly tied to in-round gameplay mechanics beyond determining round winners."
  },
  "level_system": {
    "number_of_levels": 3,
    "level_progression_rule": "Player advances to the next level by winning 2 out of 3 rounds against the AI opponents for the current level.",
    "level_indicator": "Displayed as 'Level X / 3 | Round Y / 3' in the top-left corner of the screen during gameplay.",
    "level_details": [
      {
        "level_name": "Level 1: Novice Skat",
        "difficulty": "Easy",
        "differences": "AI opponents play randomly. Bidding AI is basic (will bid the lowest possible value if hand is suitable for any game, otherwise passes). Declarer AI will pick the first valid trump suit it finds in its hand, prioritizing simplicity over strategy.",
        "advancement": "Win 2 out of 3 rounds against the Novice AI.",
        "transition_display": "Full-screen overlay: 'Level 1 Complete! Total Score: [Cumulative Score]'. Buttons: 'Next Level', 'Main Menu'."
      },
      {
        "level_name": "Level 2: Skat Apprentice",
        "difficulty": "Medium",
        "differences": "AI opponents use basic heuristics (e.g., will try to follow suit, play high cards if winning a trick, save trumps for later, try to break declarer's trump). Bidding AI is more aggressive, considering basic card values and potential game types. Declarer AI will prioritize 'Grand' or strong trump suits with good Jacks.",
        "advancement": "Win 2 out of 3 rounds against the Apprentice AI.",
        "transition_display": "Full-screen overlay: 'Level 2 Complete! Total Score: [Cumulative Score]'. Buttons: 'Next Level', 'Main Menu'."
      },
      {
        "level_name": "Level 3: Skat Master Challenge",
        "difficulty": "Hard",
        "differences": "AI opponents employ more advanced strategies (e.g., card counting, blocking declarer, strategically leading with strong suits/trumps, recognizing opponent's intentions). Bidding AI is sophisticated, attempting to overbid the player strategically or secure optimal games for itself. Declarer AI performs deeper analysis of its hand for the best possible game outcome and trick-taking strategy.",
        "advancement": "Win 2 out of 3 rounds against the Master AI.",
        "transition_display": "Full-screen overlay: 'You are the Skat Master! Final Score: [Cumulative Score]'. Buttons: 'Main Menu'."
      }
    ]
  },
  "simplifications": [
    "Multiplayer: Original 'live opponents' converted to single-player against two AI opponents.",
    "League System: The 'competitive league system' is replaced by a linear, 3-level progression system with increasing AI difficulty.",
    "Rules: Only a single, standard 'Tournament' Skat ruleset will be implemented. 'Casual' rules and any other complex variations are omitted.",
    "Social Features: No 'Skat Treff' social components, persistent player accounts, or online leaderboards. High scores are stored locally.",
    "Card Deck Designs: Limited to 3 static visual options selectable at game setup, not extensive customization.",
    "Skat Scoring: The complex calculation of a 'game value' for Skat (based on base value, suit, number of jacks, etc.) is simplified. Instead, points are awarded based on round win/loss, with specific bonuses for outcomes like 'Schneider' or 'Schwarz', rather than calculating and applying the full game value multiplier.",
    "Hotkeys: Provided as secondary options for convenience, but mouse interaction remains the primary and fully functional control method."
  ],
  "implementation_notes": "All visual rendering and interaction logic should be implemented using p5.js. Matter.js is not required for this card game's physics. The player's cumulative score must be continuously displayed in the top-right corner of the screen during gameplay. Level progression is strictly tied to winning 2 out of 3 rounds within each specific level. High scores should be stored and retrieved using the browser's `localStorage` API."
}
